import{a as e,_ as a}from"./chunks/Props_header.D0ErSKhl.js";import{_ as s,c as o,o as n,ag as r}from"./chunks/framework.Dnsuz9ka.js";const b=JSON.parse('{"title":"Components and props","description":"","frontmatter":{"title":"Components and props"},"headers":[],"relativePath":"props/general.md","filePath":"props/general.md"}'),i={name:"props/general.md"};function l(d,t,h,p,g,c){return n(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="components-and-props" tabindex="-1">Components and props <a class="header-anchor" href="#components-and-props" aria-label="Permalink to &quot;Components and props&quot;">​</a></h1><p>The <strong>Props</strong> tab shows the <strong>Vue instance tree</strong> on the page: component names, link to the root DOM node, and props summaries. Full values load when you select a row; you can edit and write back where supported.</p><p><strong>Inspect mode</strong>, <strong>favorites</strong>, and the <strong>component blacklist</strong> are covered on separate pages: <a href="/qa-tools/docs/props/inspect.html">Inspect</a>, <a href="/qa-tools/docs/props/favorite.html">Favorites</a>, <a href="/qa-tools/docs/props/blacklist.html">Blacklist</a>.</p><h2 id="top-toolbar" tabindex="-1">Top toolbar <a class="header-anchor" href="#top-toolbar" aria-label="Permalink to &quot;Top toolbar&quot;">​</a></h2><p><img src="'+e+'" alt="Props, область заголовка"></p><h3 id="component-search" tabindex="-1">Component search <a class="header-anchor" href="#component-search" aria-label="Permalink to &quot;Component search&quot;">​</a></h3><p>The search field supports several modes. Active criteria come from <strong>Search by</strong> next to the input. The same options can be preset in <strong>Options</strong> for this tab.</p><table tabindex="0"><thead><tr><th>Mode</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Name</strong></td><td>filter by component name</td></tr><tr><td><strong>Label</strong></td><td>match <code>label</code> string / suitable instance metadata</td></tr><tr><td><strong>Root</strong></td><td>match root element information</td></tr><tr><td><strong>Key</strong></td><td>prop names (including nested), deep search on the page</td></tr><tr><td><strong>Value</strong></td><td>prop values (including nested), query on the page</td></tr></tbody></table><p><strong>Key</strong> and <strong>Value</strong> use a minimum query length (default <strong>2</strong> characters; configurable in inspector search settings).</p><p><strong>Partial vs exact.</strong> If the query is <strong>not</strong> wrapped in quotes, enabled text modes use <strong>substring</strong> matching (case-insensitive). <strong>Exact</strong> whole-string match applies when the <strong>entire</strong> search text is wrapped in <strong>double quotes</strong> <code>&quot;...&quot;</code>.</p><p><strong>Inspect</strong> next to search picks a node on the page to filter the list; see <a href="/qa-tools/docs/props/inspect.html">Inspect</a>.</p><h3 id="status-chips" tabindex="-1">Status chips <a class="header-anchor" href="#status-chips" aria-label="Permalink to &quot;Status chips&quot;">​</a></h3><p>Right side of <strong>Props</strong>:</p><table tabindex="0"><thead><tr><th>Item</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Filtered</strong> (amber badge)</td><td>A page-element filter (<strong>Inspect</strong>) is active. Click clears the filter and restores the full list.</td></tr><tr><td><strong>N</strong> or <strong>N/M</strong></td><td>Visible rows after filtering; with a non-empty search, <strong>M</strong> is total components in the snapshot.</td></tr><tr><td><strong>Favorites</strong> ★</td><td>Matches between the current tree and saved favorites. Click opens <strong>Options</strong> favorites.</td></tr><tr><td><strong>Update</strong></td><td><strong>Refresh</strong> button and last snapshot time (<code>lastUpdated</code>).</td></tr></tbody></table><h2 id="work-area" tabindex="-1">Work area <a class="header-anchor" href="#work-area" aria-label="Permalink to &quot;Work area&quot;">​</a></h2><p><img src="'+a+`" alt="Props, полноэкранный режим"></p><h3 id="component-list" tabindex="-1">Component list <a class="header-anchor" href="#component-list" aria-label="Permalink to &quot;Component list&quot;">​</a></h3><p>Left: the component table. Main columns (visibility in table settings):</p><ul><li><strong>Name</strong> — component name;</li><li><strong>Root Element</strong> — root DOM info for the instance (tag, classes, id when available);</li><li><strong>Received</strong> — count of props actually passed;</li><li><strong>Declared</strong> — count of props declared on the component.</li></ul><p>Hovering a row highlights the matching node in the page.</p><p>The row context menu and star connect to <a href="/qa-tools/docs/props/favorite.html">Favorites</a> and <a href="/qa-tools/docs/props/blacklist.html">Blacklist</a>.</p><h2 id="component-details" tabindex="-1">Component details <a class="header-anchor" href="#component-details" aria-label="Permalink to &quot;Component details&quot;">​</a></h2><p>Selecting a component row opens a detail panel for that component.</p><h3 id="summary-header" tabindex="-1">Summary header <a class="header-anchor" href="#summary-header" aria-label="Permalink to &quot;Summary header&quot;">​</a></h3><p>The top of the panel shows:</p><ul><li>component name;</li><li>short <strong>root DOM</strong> info (tag and classes);</li><li>size of the serialized <strong>Received</strong> tab payload;</li><li>an <strong>Updated:</strong> line with the last update time for the node data.</li></ul><h3 id="component-data" tabindex="-1">Component data <a class="header-anchor" href="#component-data" aria-label="Permalink to &quot;Component data&quot;">​</a></h3><p>Two tabs below:</p><table tabindex="0"><thead><tr><th>Tab</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Received</strong></td><td>props actually passed; view and edit supported</td></tr><tr><td><strong>Declared</strong></td><td>declared prop definitions (<strong>rawProps</strong>); view only</td></tr></tbody></table><p>Both tabs are always available.</p><p>The active tab is shown as <strong>JSON</strong>—text or tree—according to inspector settings.</p><p>The editor supports <strong>copying</strong> the contents.</p><h3 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h3><ul><li><strong>← Back</strong> closes details and returns to the table;</li><li><strong>Esc</strong> in edit mode discards edits;</li><li><strong>Esc</strong> outside edit mode returns to the list.</li></ul><h3 id="controls" tabindex="-1">Controls <a class="header-anchor" href="#controls" aria-label="Permalink to &quot;Controls&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Control</th><th>Purpose</th></tr></thead><tbody><tr><td><strong>Star</strong></td><td>add or remove from favorites; always available</td></tr><tr><td><strong>Refresh</strong></td><td>re-fetch the selected component from the page; temporarily disabled while a refresh runs; <strong>hidden</strong> in <strong>Edit</strong> mode</td></tr><tr><td><strong>Edit</strong></td><td>enter edit mode; <strong>only on the Received</strong> tab</td></tr></tbody></table><p>Button order in the header (view mode): <strong>Star → Refresh → Edit</strong>.</p><h3 id="edit-mode" tabindex="-1">Edit mode <a class="header-anchor" href="#edit-mode" aria-label="Permalink to &quot;Edit mode&quot;">​</a></h3><p><strong>Edit</strong> applies <strong>only</strong> to the <strong>Received</strong> tab.</p><p>When editing, <strong>Refresh</strong> and <strong>Edit</strong> become <strong>Cancel</strong> and <strong>Save</strong>. <strong>Star</strong> stays available.</p><table tabindex="0"><thead><tr><th>Before editing</th><th>In edit mode</th></tr></thead><tbody><tr><td><strong>Refresh</strong></td><td><strong>Cancel</strong> — revert the draft to the last loaded props and leave edit mode</td></tr><tr><td><strong>Edit</strong></td><td><strong>Save</strong> — write changes to the app</td></tr></tbody></table><ul><li><strong>Save</strong> is disabled if JSON fails validation;</li><li>changes apply only after <strong>Save</strong>;</li><li>if save fails, edit mode may remain—watch UI messages and the console.</li></ul><p>The <strong>favorite</strong> star in this panel and in the table is described on <a href="/qa-tools/docs/props/favorite.html">Favorites</a>.</p><p>Card data reflects the <strong>last successful</strong> update for the selected node—use <strong>Refresh</strong> in the detail header to re-query props from the page, or toolbar <strong>Refresh</strong> on <strong>Props</strong> for a full snapshot refresh.</p><h2 id="display-limits" tabindex="-1">Display limits <a class="header-anchor" href="#display-limits" aria-label="Permalink to &quot;Display limits&quot;">​</a></h2><h3 id="reading-limits" tabindex="-1">Reading limits <a class="header-anchor" href="#reading-limits" aria-label="Permalink to &quot;Reading limits&quot;">​</a></h3><p><strong>Props on demand:</strong> opening a card reads and serializes values for the detail panel; heavy objects hit serializer limits (below).</p><p>The light table sends metadata and counts without full serialization of every value on each update.</p><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><p>There is no fixed “N rows like <strong>Network</strong>” cap for <strong>Props</strong>: size depends on component count and injected-side cache policy (snapshots are pruned where a node is not expanded and not needed).</p><p>To avoid blocking the page main thread, prop serialization applies limits including:</p><ul><li>time budget per serialization pass;</li><li>max nesting depth and array/object size;</li><li>long string truncation and a cap on nodes per response.</li></ul><p>Very large or cyclic structures may appear incomplete or marked as truncated—expected safeguard behavior.</p><h2 id="how-it-works" tabindex="-1">How it works <a class="header-anchor" href="#how-it-works" aria-label="Permalink to &quot;How it works&quot;">​</a></h2><h3 id="when-collection-starts" tabindex="-1">When collection starts <a class="header-anchor" href="#when-collection-starts" aria-label="Permalink to &quot;When collection starts&quot;">​</a></h3><p>The Props module attaches <strong>after Vue is detected</strong> on the page (unlike <strong>Network</strong>, which starts with the general inspector script). Until Vue initializes or the inspector is injected in the tab, the component list stays empty.</p><p>After the first successful load you can refresh manually (<strong>Refresh</strong>) or on a schedule (<strong>auto refresh</strong> in <strong>Options</strong>).</p><h3 id="what-is-monitored" tabindex="-1">What is monitored <a class="header-anchor" href="#what-is-monitored" aria-label="Permalink to &quot;What is monitored&quot;">​</a></h3><ol><li><strong>Structure</strong> — walking Vue instances yields a flat list with metadata (name, label when present, element binding, <strong>received</strong> and <strong>declared</strong> counts without full values every frame).</li><li><strong>Props on selection</strong> — full values load when you open a card (lazy).</li></ol><p>The same channel refreshes after <strong>Toolbar</strong> <strong>Refresh</strong>, respecting the active <strong>blacklist</strong> (name filtering during collection—see <a href="/qa-tools/docs/props/blacklist.html">Blacklist</a>).</p><h3 id="messaging-model" tabindex="-1">Messaging model <a class="header-anchor" href="#messaging-model" aria-label="Permalink to &quot;Messaging model&quot;">​</a></h3><p>The panel does not read Vue memory directly: it sends a message to the page; injected code walks instances and returns serialized data.</p><p>Simplified flow:</p><div class="language-js vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Illustration: UI requests the component list; the page scanner builds structure.</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">const</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> response</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> await</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> bridge.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">send</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  type: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;COLLECT_VUE_COMPONENTS&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  forceRefresh: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  blacklist: { active: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;SomeNoise&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">], inactive: [] },</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">})</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// response.components — names, uid, prop counts, Root Element strings…</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Full prop payloads load separately when a card opens (lazy).</span></span></code></pre></div><p>This separates the <strong>light table</strong> from <strong>heavy prop reads</strong> for the selected node only.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/props/inspect.html">Inspect — pick a component on the page</a></li><li><a href="/qa-tools/docs/props/favorite.html">Favorites</a></li><li><a href="/qa-tools/docs/props/blacklist.html">Blacklist</a></li><li><a href="/qa-tools/docs/options/update_settings.html">Update settings &amp; auto refresh</a> (<strong>Options</strong>)</li></ul>`,67)])])}const f=s(i,[["render",l]]);export{b as __pageData,f as default};
